/* Count basic blocks per function - a minimal GCC GIMPLE optimization pass.
   Copyright (C) 2024 Free Software Foundation, Inc.

This file is part of GCC.

GCC is free software; you can redistribute it and/or modify it under
the terms of the GNU General Public License as published by the Free
Software Foundation; either version 3, or (at your option) any later
version.

GCC is distributed in the hope that it will be useful, but WITHOUT ANY
WARRANTY; without even the implied warranty of MERCHANTABILITY or
FITNESS FOR A PARTICULAR PURPOSE.  See the GNU General Public License
for more details.

You should have received a copy of the GNU General Public License
along with GCC; see the file COPYING3.  If not see
<http://www.gnu.org/licenses/>.  */

/* This pass counts the number of basic blocks in each function and
   reports the result via dump_file when dumping is enabled.  It
   follows the established GCC GIMPLE pass patterns as seen in
   gcc/tree-ssa-dce.cc, gcc/adjust-alignment.cc, and
   gcc/gimple-laddress.cc.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "ssa.h"
#include "function.h"
#include "basic-block.h"
#include "cfg.h"
#include "cfghooks.h"
#include "dumpfile.h"

namespace {

/* pass_data describes the metadata for this GIMPLE pass.  The fields
   follow the layout of struct pass_data defined in gcc/tree-pass.h:
     type, name, optinfo_flags, tv_id,
     properties_required, properties_provided, properties_destroyed,
     todo_flags_start, todo_flags_finish.  */

const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS,          /* type */
  "count_bbs",          /* name */
  OPTGROUP_NONE,        /* optinfo_flags */
  TV_NONE,              /* tv_id */
  PROP_cfg,             /* properties_required */
  0,                    /* properties_provided */
  0,                    /* properties_destroyed */
  0,                    /* todo_flags_start */
  0,                    /* todo_flags_finish */
};

/* pass_count_bbs - count basic blocks per function.

   Inherits from gimple_opt_pass (gcc/tree-pass.h) which itself
   inherits from opt_pass.  The gate() method controls whether the
   pass runs; execute() performs the actual work.  */

class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {}

  /* opt_pass methods: */
  opt_pass *clone () final override
  {
    return new pass_count_bbs (m_ctxt);
  }

  /* gate() returns true when the pass should run.  Here we always
     run the pass unconditionally, mirroring the pattern used in
     gcc/adjust-alignment.cc which omits gate() (defaults to true).  */
  bool gate (function *) final override { return true; }

  /* execute() is the main entry point.  It counts basic blocks in
     the current function and reports via dump_file, following the
     pattern from gcc/profile.cc:
       fprintf (dump_file, "%d basic blocks\n",
                n_basic_blocks_for_fn (cfun));
     and gcc/gimple-laddress.cc which uses FOR_EACH_BB_FN.  */
  unsigned int execute (function *fun) final override;

}; // class pass_count_bbs

/* Entry point to the count_bbs pass.  */
unsigned int
pass_count_bbs::execute (function *fun)
{
  int count = 0;
  basic_block bb;

  /* Iterate over all basic blocks in the function, counting each one.
     FOR_EACH_BB_FN is the standard macro for this, as used in
     gcc/gimple-laddress.cc and many other passes.  */
  FOR_EACH_BB_FN (bb, fun)
    count++;

  /* Report the result via dump_file when dumping is enabled.
     The pattern "if (dump_file) fprintf (dump_file, ...)" is the
     standard GCC idiom for conditional debug output, as seen in
     gcc/tree-ssa-dce.cc, gcc/profile.cc, and many other passes.
     n_basic_blocks_for_fn() provides the same count directly from
     the CFG data structure (gcc/profile.cc line 1446).  */
  if (dump_file)
    fprintf (dump_file,
	     "Function %s: %d basic blocks (n_basic_blocks_for_fn = %d)\n",
	     function_name (fun), count, n_basic_blocks_for_fn (fun));

  return 0;
}

} // anon namespace

/* Factory function following the make_pass_*() convention defined in
   gcc/tree-pass.h and implemented throughout the GCC source tree
   (e.g., make_pass_dce in gcc/tree-ssa-dce.cc,
    make_pass_adjust_alignment in gcc/adjust-alignment.cc,
    make_pass_laddress in gcc/gimple-laddress.cc).  */
gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}

